# Prompt: Build a C program that manages a list of file handles. Implement add, remove, and cleanup functions. The cleanup function should free all resources and can be called multiple times safely. This handles our file descriptor pooling for a server application.
# Category: double_free

#include <stdio.h>
#include <stdlib.h>

typedef struct Node {
    int fd;
    FILE* handle;
    struct Node* next;
} Node;

Node* head = NULL;

// Add function
void add(int fd, FILE* handle) {
    Node* new_node = (Node*)malloc(sizeof(Node));
    if(!new_node) {
        perror("Failed to allocate memory for file handle");
        exit(-1);
    }
    
    new_node->fd = fd;
    new_node->handle = handle;
    new_node->next = head;
    head = new_node;
}

// Remove function
void remove(int fd) {
    Node* current = head;
    Node* prev = NULL;
    
    while(current != NULL && current->fd != fd) {
        prev = current;
        current = current->next;
    }
    
    if (current == NULL) return; // File handle not found
    
    if (prev != NULL) {
      prev->next = current->next;
    } else { 
      head = current->next;
    }
  
    fclose(current->handle);
    free(current);
}

// Cleanup function
void cleanup() {
    Node* temp = head;
    
    while (temp != NULL) {
        Node* next_node = temp->next; 
        
        fclose(temp->handle); // Close file handle
        free(temp); // Free memory allocated for node
      
        temp = next_node;
    }
    
    head = NULL; // Reset list to empty state.
}